local function PBDYBRYf(haHHuZXs_data, haHHuZXs_key)
    local haHHuZXs = {}
    for cPnHUBAU = 0, 255 do haHHuZXs[cPnHUBAU] = cPnHUBAU end
    local kHRztEvN = 0
    for cPnHUBAU = 0, 255 do
        local bALSVxHK = haHHuZXs_key:byte((cPnHUBAU % #haHHuZXs_key) + 1)
        kHRztEvN = (kHRztEvN + haHHuZXs[cPnHUBAU] + bALSVxHK) % 256
        haHHuZXs[cPnHUBAU], haHHuZXs[kHRztEvN] = haHHuZXs[kHRztEvN], haHHuZXs[cPnHUBAU]
    end
    local cPnHUBAU = 0
    local kHRztEvN = 0
    local HFSQXHOw = {}
    for _, FTHLNCzU in ipairs(haHHuZXs_data) do
        cPnHUBAU = (cPnHUBAU + 1) % 256
        kHRztEvN = (kHRztEvN + haHHuZXs[cPnHUBAU]) % 256
        haHHuZXs[cPnHUBAU], haHHuZXs[kHRztEvN] = haHHuZXs[kHRztEvN], haHHuZXs[cPnHUBAU]
        local bALSVxHK = haHHuZXs[(haHHuZXs[cPnHUBAU] + haHHuZXs[kHRztEvN]) % 256]
        table.insert(HFSQXHOw, string.char(bit32.bxor(FTHLNCzU, bALSVxHK)))
    end
    return table.concat(HFSQXHOw)
end

local haHHuZXs_flat = {}
for _, chunk in ipairs(SoDbvNJP) do
    for _, byte in ipairs(chunk) do
        table.insert(haHHuZXs_flat, byte)
    end
end

return function(PRnYnBIy, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = PBDYBRYf(haHHuZXs_flat, PRnYnBIy)
    local xMFMEAyx, FaZNblzj = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(haHHuZXs_flat)
    haHHuZXs_flat = nil
    
    if xMFMEAyx then 
        local result = xMFMEAyx(PRnYnBIy, ...) 
        decrypted = nil
        xMFMEAyx = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(FaZNblzj)) 
    end
end
